    {
        _statusStrip = new StatusStrip();
        // .NET 9: StatusStrip default render mode changed. Explicitly set
        // Professional to preserve the .NET 8 appearance.
        _statusStrip.RenderMode = ToolStripRenderMode.Professional;
        Controls.Add(_statusStrip);
    }

    /// <summary>
    /// Shows a dropdown editor, guarding against the null control that
    /// .NET 9 now rejects with ArgumentNullException.
    /// </summary>
    public static void ShowDropDown(IWindowsFormsEditorService editorService, Control control)
    {
        // .NET 9: DropDownControl(null) now throws ArgumentNullException.
        if (control is null)
            return;

        editorService.DropDownControl(control);
    }
}

